import React from 'react';

function App() {
  return (
    <div style={{ textAlign: 'center', marginTop: '50px', fontFamily: 'Arial' }}>
      <h1 style={{ color: '#2d5a27' }}>🌱 Agri-AI Platform</h1>
      <p>Welcome! Please select your role to continue:</p>

      <div style={{ marginTop: '30px' }}>
        <button style={btnStyle}>Login as Buyer</button>
        <button style={{ ...btnStyle, backgroundColor: '#4a7c44' }}>Login as Seller</button>
      </div>

      <div style={{ marginTop: '50px', padding: '20px', border: '1px solid #ddd', display: 'inline-block' }}>
        <h3>✨ AI Insight of the Day</h3>
        <p>Tomato prices are expected to rise by 15% next month. Buy now!</p>
      </div>
    </div>
  );
}

const btnStyle = {
  padding: '10px 20px',
  margin: '10px',
  fontSize: '16px',
  cursor: 'pointer',
  backgroundColor: '#2d5a27',
  color: 'white',
  border: 'none',
  borderRadius: '5px'
};

export default App;
